content:
/* Materia (Light) Theme Variables */
:root {
    --theme-bg: #ffffff;
    --theme-fg: #212121;
    --theme-primary: #2196f3;
    --theme-secondary: #666666;
    --theme-tertiary: #F8F9FA;
    --theme-success: #4CAF50;
    --theme-info: #00BCD4;
    --theme-warning: #FFC107;
    --theme-danger: #F44336;
    --theme-border: #e0e0e0;
    --theme-table-head: rgba(33, 150, 243, 0.1);
    --theme-table-bg: #FFFFFF;
    /* Paper White */
    --theme-table-color: #212121;
    /* Near Black */
    --theme-table-border-color: #E0E0E0;
    /* Light Gray Divider */
    --theme-table-accent-bg: transparent;
    --theme-table-striped-color: #212121;
    --theme-table-striped-bg: #F5F5F5;
    /* Subtle Zebra Stripe */
    --theme-table-hover-color: #212121;
    --theme-table-hover-bg: #EEEEEE;
    /* Soft Hover Effect */
    --theme-table-active-color: #FFFFFF;
    --theme-table-active-bg: #2196F3;
    /* Material Primary Blue */
    --theme-plotly-bg: #FFFFFF;
    --theme-plotly-plot-bg: #F8F9FA;
    --theme-plotly-font: #212121;
    --theme-plotly-grid: #E0E0E0;
    --theme-plotly-primary: #2196F3;
    --theme-plotly-fillcolor: #A3D5FB;
    /* Light Blue; Secondary; for shading */
    --theme-plotly-plot_bgcolor: #F8F9FA;
    /* Light Gray; Tertiary; for background */
    --theme-plotly-gridcolor: #F8F9FA;
    /* Light Gray; Tertiary; for grid lines */
    --theme-plotly-danger: #F44336;
    --theme-plotly-warning: #FFC107;
    --theme-plotly-success: #4CAF50;
    --theme-plotly-info: #00BCD4;
    --theme-plotly-xaxis_gridcolor: #E0E0E0;
    --theme-plotly-yaxis_gridcolor: #E0E0E0;
    --theme-plotly-xaxis_linecolor: #212121;
    --theme-plotly-yaxis_linecolor: #212121;
}

/* Slate (Dark) Theme Variables */
[data-bs-theme="dark"] {
    --theme-bg: #272b30;
    --theme-fg: #c8c8c8;
    --theme-primary: #7a8288;
    --theme-secondary: #3A3F44;
    --theme-tertiary: #272b30;
    --theme-success: #62C462;
    --theme-info: #5BC0DE;
    --theme-warning: #F89406;
    --theme-danger: #EE5F5B;
    --theme-border: #444444;
    --theme-table-head: rgba(122, 130, 136, 0.2);
    --theme-table-bg: #272B30;
    /* Main Dark Background */
    --theme-table-color: #C8C8C8;
    /* Muted White/Gray Text */
    --theme-table-border-color: #1C1E22;
    /* Deep Charcoal Borders */
    --theme-table-accent-bg: transparent;
    --theme-table-striped-color: #C8C8C8;
    --theme-table-striped-bg: #2E3338;
    /* Slightly Lighter Gray Stripe */
    --theme-table-hover-color: #FFFFFF;
    /* Brighter Text on Hover */
    --theme-table-hover-bg: #3E444C;
    /* Interactive Slate Gray */
    --theme-table-active-color: #FFFFFF;
    --theme-table-active-bg: #7A8288;
    /* Slate Primary Gray */
    --theme-plotly-bg: #272B30;
    --theme-plotly-plot-bg: #272B30;
    --theme-plotly-font: #C8C8C8;
    --theme-plotly-grid: #3E444C;
    --theme-plotly-primary: #7A8288;
    /* Slate Primary Gray */
    --theme-plotly-fillcolor: #51565A;
    /* Interactive Slate Gray; Secondary; for shading */
    --theme-plotly-plot_bgcolor: #272B30;
    /* Main Dark Background */
    --theme-plotly-gridcolor: #3E444C;
    /* Interactive Slate Gray; Tertiary; for grid lines */
    --theme-plotly-danger: #EE5F5B;
    --theme-plotly-warning: #F89406;
    --theme-plotly-success: #62C462;
    --theme-plotly-info: #5BC0DE;
    --theme-plotly-xaxis_gridcolor: #3E444C;
    --theme-plotly-yaxis_gridcolor: #3E444C;
    --theme-plotly-xaxis_linecolor: #1C1E22;
    --theme-plotly-yaxis_linecolor: #1C1E22;
}

body {
    background-color: var(--theme-bg);
    color: var(--theme-fg);
    font-family: 'Times New Roman', serif;
    transition: background-color 0.3s, color 0.3s;
}

/* Journal Style Table Formatting */
.table {
    background-color: var(--theme-table-bg) !important;
    color: var(--theme-table-color) !important;
    border-color: var(--theme-table-border-color) !important;
    font-family: 'Times New Roman', serif !important;
    font-size: 14px;
}

.table thead {
    background-color: var(--theme-table-bg) !important;
    color: var(--theme-table-color) !important;
    border-color: var(--theme-table-border-color) !important;
    font-family: 'Times New Roman', serif !important;
    font-size: 16px;
}

pre {
    color: var(--theme-fg) !important;
    font-family: 'Times New Roman', serif !important;
    font-size: 16px;
    padding: 10px;
    border-radius: 5px;
}

/* .interpretation class */
.interpretation {
    font-style: italic;
    opacity: 0.8;
    margin-top: 10px;
    border-left: 3px solid var(--theme-primary);
    padding-left: 10px;
}

/* .sig-legend class */
.sig-legend {
    font-family: 'Times New Roman', serif;
    font-size: 12px;
    opacity: 0.7;
    margin-bottom: 2rem;
}

/* Appendix Styling */
.appendix-header {
    font-weight: bold;
    color: var(--theme-primary);
    border-bottom: 2px solid var(--theme-border);
    margin-top: 20px;
    padding-bottom: 5px;
    margin-bottom: 10px;
}

.term {
    font-weight: bold;
    color: var(--theme-primary);
    display: block;
    margin-top: 8px;
}

.definition {
    display: block;
    margin-bottom: 4px;
    padding-left: 15px;
    border-left: 2px solid var(--theme-border);
}

.footnote {
    font-size: 12px;
    font-style: italic;
    opacity: 0.7;
    border-top: 1px solid var(--theme-border);
    margin-top: 40px;
    padding-top: 10px;
}

/* Disclaimer styling */
.disclaimer-header {
    font-weight: bold;
    color: var(--theme-primary);
    border-bottom: 2px solid var(--theme-border);
    margin-top: 20px;
    padding-bottom: 5px;
    margin-bottom: 10px;
}

/* .plotly class */
.plotly {
    background: var(--theme-plotly-plot-bg);
    background-color: var(--theme-plotly-bg);
    font: var(--theme-plotly-font);
    /* Text Color */
    grid: var(--theme-plotly-grid);
    /* Grid Color */
    fill: var(--theme-plotly-danger);
    /* Fill Color or Marker Color */
    stroke: var(--theme-plotly-primary);
    /* Line Color */
    stroke-width: 0.2px;
    /* Marker Size */
    font-size: 12px;
    font-family: 'Times New Roman', serif;
    transition: background-color 0.1s, color 0.1s;
}

/* Un-bold and left-align headers ONLY for your statsmodels outputs */
.sm-summary-table th {
    font-weight: normal !important;
    text-align: left !important;
}

/* Force left-alignment and text-spacing on data cells to fix the shift */
.sm-summary-table td {
    text-align: left !important;
    padding-right: 25px !important;
    /* Generates clean spacing between columns */
}

/* Hide empty lines or ghost borders injected by statsmodels */
.sm-summary-table tr:empty,
.sm-summary-table td:empty {
    border: none !important;
}

/* Erase the thick Bootstrap theme line beneath the column headers */
.sm-summary-table table> :not(:first-child),
.sm-summary-table .table> :not(:first-child) {
    border-top: none !important;
    border-top-width: 0 !important;
}

/* Double check and erase any remaining standard table borders */
.sm-summary-table th,
.sm-summary-table td,
.sm-summary-table thead,
.sm-summary-table tbody {
    border: none !important;
    border-bottom: none !important;
    border-top: none !important;
}
